55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const CURSED_SURCHARGE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_RATE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const FIRST_INSURANCE_RATE = 0.1;
62	const LOYALTY_DISCOUNT_RATE = 0.2;
63	const LOYALTY_YEARS_THRESHOLD = 2;
64	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
65	  sword: 100,
66	  amulet: 60,
67	  staff: 80,
68	  potion: 40,
69	  rune: 25,
70	  moonstone: 25,
71	};
72	
73	const basePremium = (item: Item): number =>
74	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
75	
76	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
77	
78	const groupByType = (items: Item[]): Map<string, Item[]> => {
79	  const groups = new Map<string, Item[]>();
80	  for (const item of items) {
81	    const existing = groups.get(item.type) ?? [];
82	    existing.push(item);
83	    groups.set(item.type, existing);
84	  }
85	  return groups;
86	};
87	
88	const sumBasePremiums = (items: Item[]): number =>
89	  items.reduce((sum, item) => sum + basePremium(item), 0);
90	
91	const groupTotal = (type: string, group: Item[]): number => {
92	  if (group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type)) {
93	    return COMPONENT_BLOCK_PRICE;
94	  }
95	  return sumBasePremiums(group);
96	};
97	
98	const policyBase = (items: Item[]): number =>
99	  Array.from(groupByType(items)).reduce(
100	    (sum, [type, group]) => sum + groupTotal(type, group),
101	    0,
102	  );
103	
104	const perItemSurcharge = (
105	  items: Item[],
106	  predicate: (item: Item) => boolean,
107	  rate: number,
108	): number =>
109	  items.reduce(
110	    (sum, item) => sum + (predicate(item) ? basePremium(item) * rate : 0),
111	    0,
112	  );
113	
114	const isCursed = (item: Item): boolean => item.cursed === true;
115	
116	const isHighlyEnchanted = (item: Item): boolean =>
117	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
118	
119	const cursedSurcharge = (items: Item[]): number =>
120	  perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE);
121	
122	const highEnchantmentSurcharge = (items: Item[]): number =>
123	  perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE);
124	
125	const firstInsuranceSurcharge = (base: number): number =>
126	  base * FIRST_INSURANCE_RATE;
127	
128	const loyaltyDiscount = (base: number, customer: Customer): number =>
129	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
130	    ? base * LOYALTY_DISCOUNT_RATE
131	    : 0;
132	
133	const quotePremium = (items: Item[], customer: Customer): number => {
134	  const base = policyBase(items);
135	  const modifiedBase =
136	    base +
137	    cursedSurcharge(items) +
138	    highEnchantmentSurcharge(items) +
139	    firstInsuranceSurcharge(base) -
140	    loyaltyDiscount(base, customer);
141	  return Math.ceil(modifiedBase) + PROCESSING_FEE;
142	};
