144	export const processScenario = (scenario: Scenario): ScenarioOutput => {
145	  const step = scenario.steps[0] as QuoteStep;
146	  return {
147	    results: [{ premium: quotePremium(step.items, scenario.customer) }],
148	  };
149	};
